#!/usr/bin/env bash
# Ultra Terminal - macOS installer (self-extracting)
set -e

INSTALL_DIR="$HOME/.local/share/UltraTerminal"
BIN_DIR="$HOME/.local/bin"
APP_LINK="$BIN_DIR/ut"

mkdir -p "$INSTALL_DIR" "$BIN_DIR"

echo "Installing Ultra Terminal to $INSTALL_DIR..."

# Decode embedded payload
UT_SH_B64=''
RUNTIMES_B64=''

if command -v base64 >/dev/null 2>&1; then
    echo "$UT_SH_B64"     | base64 -d > "$INSTALL_DIR/ut.sh"
    echo "$RUNTIMES_B64"  | base64 -d > "$INSTALL_DIR/runtimes.json"
elif command -v openssl >/dev/null 2>&1; then
    echo "$UT_SH_B64"     | openssl base64 -d -A > "$INSTALL_DIR/ut.sh"
    echo "$RUNTIMES_B64"  | openssl base64 -d -A > "$INSTALL_DIR/runtimes.json"
else
    echo "ERROR: need 'base64' or 'openssl' to decode payload."
    exit 1
fi

chmod +x "$INSTALL_DIR/ut.sh"

# wrapper executavel em ~/.local/bin/ut
cat > "$APP_LINK" <<'EOF'
#!/usr/bin/env bash
exec "$HOME/.local/share/UltraTerminal/ut.sh" "$@"
EOF
# fix $HOME expansion in wrapper (single-quoted heredoc keeps literal)
sed -i.bak "s|\\\C:\Users\pslo9|$HOME|g" "$APP_LINK" 2>/dev/null || sed -i "" "s|\\\C:\Users\pslo9|$HOME|g" "$APP_LINK"
rm -f "$APP_LINK.bak"
chmod +x "$APP_LINK"

# Verifica se ~/.local/bin esta no PATH
case ":$PATH:" in
    *":$BIN_DIR:"*) ;;
    *)
        echo ""
        echo "WARNING: $BIN_DIR is not in your PATH."
        echo "  Add to your shell rc (~/.bashrc or ~/.zshrc):"
        echo "    export PATH=\"$BIN_DIR:\$PATH\""
        ;;
esac

echo ""
echo "OK! Run: ut"
echo "Uninstall: rm -rf $INSTALL_DIR $APP_LINK"